parameters.jsCode:
const productName = ($json['Product Name'] ?? $json.product_name ?? '').trim();
const country = ($json['Country'] ?? $json.country ?? '').trim();
const industry = ($json['Industry'] ?? $json.industry ?? '').trim();
const rawCount = $json['Target Lead Count'] ?? $json.target_lead_count ?? 30;
const targetLeadCount = Math.max(1, Math.min(200, Number(rawCount) || 30));
const additionalNotes = ($json['Additional Notes'] ?? $json.additional_notes ?? '').trim();

if (!productName || !country || !industry) {
  throw new Error('Product Name, Country, and Industry are required.');
}

const productQuery = productName.replace(/\s+/g, ' ').trim();
const industryQuery = industry.replace(/\s+/g, ' ').trim();

const searchQueries = [
  `${industryQuery} companies in ${country}`,
  `${industryQuery} distributors in ${country}`,
  `${productQuery} buyers in ${country}`,
  `${productQuery} suppliers customers ${country}`,
  `site:linkedin.com/company ${industryQuery} ${country}`,
  `site:instagram.com ${industryQuery} ${country}`,
  `"custom acrylic display" ${industryQuery} ${country}`,
  `"retail display" buyer ${country}`,
];

return [{
  json: {
    agent_name: 'lead_hunter',
    task_type: 'lead_search',
    product_name: productName,
    country,
    industry,
    target_lead_count: targetLeadCount,
    additional_notes: additionalNotes,
    search_queries: searchQueries,
    task_input: {
      product_name: productName,
      country,
      industry,
      target_lead_count: targetLeadCount,
      additional_notes: additionalNotes,
      search_queries: searchQueries,
      sources: ['Google', 'LinkedIn', 'company websites'],
      status_note: 'Task created. Search execution will be added in Lead Hunter v0.2.'
    }
  }
}];

